--- 文件: D:\LLM\memory\agentmemory\src\functions\context.ts (第 1 至 220 行，共 234 行) ---
   1 | import type { ISdk } from "iii-sdk";
   2 | import type {
   3 |   Session,
   4 |   CompressedObservation,
   5 |   SessionSummary,
   6 |   ContextBlock,
   7 |   ProjectProfile,
   8 |   MemorySlot,
   9 |   Lesson,
  10 | } from "../types.js";
  11 | import { KV } from "../state/schema.js";
  12 | import { StateKV } from "../state/kv.js";
  13 | import { recordAccessBatch } from "./access-tracker.js";
  14 | import { logger } from "../logger.js";
  15 | import {
  16 |   isSlotsEnabled,
  17 |   listPinnedSlots,
  18 |   renderPinnedContext,
  19 | } from "./slots.js";
  20 | 
  21 | function estimateTokens(text: string): number {
  22 |   return Math.ceil(text.length / 3);
  23 | }
  24 | 
  25 | function escapeXmlAttr(s: string): string {
  26 |   return s
  27 |     .replace(/&/g, "&amp;")
  28 |     .replace(/"/g, "&quot;")
  29 |     .replace(/</g, "&lt;")
  30 |     .replace(/>/g, "&gt;");
  31 | }
  32 | 
  33 | export function registerContextFunction(
  34 |   sdk: ISdk,
  35 |   kv: StateKV,
  36 |   tokenBudget: number,
  37 | ): void {
  38 |   sdk.registerFunction("mem::context",
  39 |     async (data: { sessionId: string; project: string; budget?: number }) => {
  40 |       const budget = data.budget || tokenBudget;
  41 |       const blocks: ContextBlock[] = [];
  42 | 
  43 |       const [pinnedSlots, profile, lessons] = await Promise.all([
  44 |         isSlotsEnabled()
  45 |           ? listPinnedSlots(kv).catch(() => [] as MemorySlot[])
  46 |           : Promise.resolve([] as MemorySlot[]),
  47 |         kv
  48 |           .get<ProjectProfile>(KV.profiles, data.project)
  49 |           .catch(() => null),
  50 |         kv.list<Lesson>(KV.lessons).catch(() => [] as Lesson[]),
  51 |       ]);
  52 | 
  53 |       const slotContent = renderPinnedContext(pinnedSlots);
  54 |       if (slotContent) {
  55 |         blocks.push({
  56 |           type: "memory",
  57 |           content: slotContent,
  58 |           tokens: estimateTokens(slotContent),
  59 |           recency: Date.now(),
  60 |         });
  61 |       }
  62 |       if (profile) {
  63 |         const profileParts = [];
  64 |         if (profile.topConcepts.length > 0) {
  65 |           profileParts.push(
  66 |             `Concepts: ${profile.topConcepts
  67 |               .slice(0, 8)
  68 |               .map((c) => c.concept)
  69 |               .join(", ")}`,
  70 |           );
  71 |         }
  72 |         if (profile.topFiles.length > 0) {
  73 |           profileParts.push(
  74 |             `Key files: ${profile.topFiles
  75 |               .slice(0, 5)
  76 |               .map((f) => f.file)
  77 |               .join(", ")}`,
  78 |           );
  79 |         }
  80 |         if (profile.conventions.length > 0) {
  81 |           profileParts.push(`Conventions: ${profile.conventions.join("; ")}`);
  82 |         }
  83 |         if (profile.commonErrors.length > 0) {
  84 |           profileParts.push(
  85 |             `Common errors: ${profile.commonErrors.slice(0, 3).join("; ")}`,
  86 |           );
  87 |         }
  88 |         if (profileParts.length > 0) {
  89 |           const profileContent = `## Project Profile\n${profileParts.join("\n")}`;
  90 |           blocks.push({
  91 |             type: "memory",
  92 |             content: profileContent,
  93 |             tokens: estimateTokens(profileContent),
  94 |             recency: new Date(profile.updatedAt).getTime(),
  95 |           });
  96 |         }
  97 |       }
  98 | 
  99 |       // Lessons — closes the loop opened by mem::lesson-save / mem::reflect.
 100 |       // Without this block, lessons sit in KV and only surface when the agent
 101 |       // thinks to call memory_lesson_recall. Ranking puts project-scoped
 102 |       // lessons ahead of global ones, then weights by confidence; we cap at
 103 |       // 10 to keep the block bound...

